1	/**
2	 * Image export service
3	 *
4	 * Generates a single PNG image from a rendered export document.
5	 * Uses DOM-to-image rendering and inlines remote images (best-effort).
6	 */
7	import { isSafari } from '@/core/utils/browser';
8	
9	import { isEventLikeImageRenderError } from '../types/errors';
10	import type { ChatTurn, ConversationMetadata } from '../types/export';
11	import { DOMContentExtractor } from './DOMContentExtractor';
12	import { renderElementToImageBlob } from './ImageRenderService';
13	
14	export interface RenderableDocumentContent {
15	  title: string;
16	  url: string;
17	  exportedAt: string;
18	  markdown: string;
19	  html: string;
20	}
21	
22	export class ImageExportService {
23	  private static readonly PRIMARY_RENDER_MAX_ATTEMPTS = 3;
24	
25	  private static readonly PRIMARY_RENDER_RETRY_DELAY_MS = 260;
26	
27	  static async export(
28	    turns: ChatTurn[],
29	    metadata: ConversationMetadata,
30	    options: { filename: string; fontSize?: number },
31	  ): Promise<void> {
32	    const filename = options.filename.toLowerCase().endsWith('.png')
33	      ? options.filename
34	      : `${options.filename}.png`;
35	
36	    const blob = await this.renderConversationBlob(turns, metadata, options);
37	    this.downloadBlob(blob, filename);
38	  }
39	
40	  static async exportDocument(
41	    content: RenderableDocumentContent,
42	    options: { filename: string },
43	  ): Promise<void> {
44	    const filename = options.filename.toLowerCase().endsWith('.png')
45	      ? options.filename
46	      : `${options.filename}.png`;
47	
48	    const blob = await this.renderDocumentBlob(content);
49	    this.downloadBlob(blob, filename);
50	  }
51	
52	  static async renderConversationBlob(
53	    turns: ChatTurn[],
54	    metadata: ConversationMetadata,
55	    options: { fontSize?: number },
56	  ): Promise<Blob> {
57	    const container = this.createRenderContainer(turns, metadata, options.fontSize);
58	    return await this.renderContainerToBlob(container);
59	  }
60	
61	  static async renderDocumentBlob(content: RenderableDocumentContent): Promise<Blob> {
62	    const container = this.createDocumentRenderContainer(content);
63	    return await this.renderContainerToBlob(container);
64	  }
65	
66	  private static createRenderContainer(
67	    turns: ChatTurn[],
68	    metadata: ConversationMetadata,
69	    fontSize?: number,
70	  ): HTMLElement {
71	    const outer = document.createElement('div');
72	    outer.className = 'gv-image-export-container';
73	    Object.assign(outer.style, {
74	      position: 'fixed',
75	      left: '-10000px',
76	      top: '0',
77	      width: '620px',
78	      background: '#ffffff',
79	      color: '#111827',
80	      zIndex: '-1',
81	      pointerEvents: 'none',
82	    } as Partial<CSSStyleDeclaration>);
83	
84	    const title = metadata.title || 'Conversation';
85	    const date = this.formatDate(metadata.exportedAt);
86	    const headerHtml = `
87	      <header class="gv-image-export-header">
88	        <h1 class="gv-image-export-title">${this.escapeHTML(title)}</h1>
89	        <div class="gv-image-export-meta">
90	          <div>${this.escapeHTML(date)}</div>
91	          <div><a href="${this.escapeAttr(metadata.url)}">${this.escapeHTML(metadata.url)}</a></div>
92	          <div>${metadata.count} conversation turns</div>
93	        </div>
94	      </header>
95	    `;
96	
97	    const turnsHtml = turns
98	      .map((turn, idx) => {
99	        const turnIndex = idx + 1;
100	        const starred = turn.starred ? ' ⭐' : '';
101	        const userHtml = turn.userElement
102	          ? DOMContentExtractor.extractUserContent(turn.userElement).html
103	          : this.formatPlainTextAsHtml(turn.user);
104	        const assistantHtml = turn.assistantElement
105	          ? DOMContentExtractor.extractAssistantContent(turn.assistantElement).html
106	          : this.formatPlainTextAsHtml(turn.assistant);
107	
108	        if (!turn.omitEmptySections) {
109	          return `
110	          <article class="gv-image-export-turn">
111	            <div class="gv-image-export-turn-header">Turn ${turnIndex}${starred}</div>
112	            <section class="gv-image-export-block">
113	              <div class="gv-image-export-label">User</div>
114	              <div class="gv-image-export-content">${userHtml || '<em>No content</em>'}</div>
115	            </section>
116	            <section class="gv-image-export-block">
117	              <div class="gv-image-export-label">Assistant</div>
118	              <div class="gv-image-export-content">${assistantHtml || '<em>No content</em>'}</div>
119	            </section>
120	          </article>
121	        `;
122	        }
123	
124	        const hasUser = !!turn.userElement || !!turn.user.trim();
125	        const hasAssistant = !!turn.assistantElement || !!turn.assistant.trim();
126	
127	        return `
128	          <article class="gv-image-export-turn">
129	            <div class="gv-image-export-turn-header">Turn ${turnIndex}${starred}</div>
130	            ${
131	              hasUser
132	                ? `
133	            <section class="gv-image-export-block">
134	              <div class="gv-image-export-label">User</div>
135	              <div class="gv-image-export-content">${userHtml || '<em>No content</em>'}</div>
136	            </section>
137	            `
138	                : ''
139	            }
140	            ${
141	              hasAssistant
142	                ? `
143	            <section class="gv-image-export-block">
144	              <div class="gv-image-export-label">Assistant</div>
145	              <div class="gv-image-export-content">${assistantHtml || '<em>No content</em>'}</div>
