380	  private static async inlineImages(container: HTMLElement): Promise<void> {
381	    const imgs = Array.from(container.querySelectorAll('img')) as HTMLImageElement[];
382	    if (imgs.length === 0) return;
383	
384	    const blobToDataUrl = async (blob: Blob): Promise<string | null> => {
385	      try {
386	        return await new Promise<string>((resolve, reject) => {
387	          const reader = new FileReader();
388	          reader.onerror = () => reject(new Error('readAsDataURL failed'));
389	          reader.onload = () => resolve(String(reader.result || ''));
390	          reader.readAsDataURL(blob);
391	        });
392	      } catch {
393	        return null;
394	      }
395	    };
396	
397	    const toDataUrl = async (url: string): Promise<string | null> => {
398	      if (!/^https?:\/\//i.test(url)) return null;
399	
400	      // Try content-script fetch first
401	      try {
402	        const resp = await fetch(url, { credentials: 'include', mode: 'cors' as RequestMode });
403	        if (resp.ok) {
404	          const blob = await resp.blob();
405	          const data = await blobToDataUrl(blob);
406	          if (data) return data;
407	        }
408	      } catch {
409	        /* ignore */
410	      }
411	
412	      // Fallback to background fetch (bypasses page CORS)
413	      try {
414	        const data = await new Promise<string | null>((resolve) => {
415	          try {
416	            chrome.runtime?.sendMessage?.({ type: 'gv.fetchImage', url }, (resp) => {
417	              if (resp && resp.ok && resp.base64) {
418	                const contentType = String(resp.contentType || 'application/octet-stream');
419	                resolve(`data:${contentType};base64,${resp.base64}`);
420	              } else {
421	                resolve(null);
422	              }
423	            });
424	          } catch {
425	            resolve(null);
426	          }
427	        });
428	        if (data) return data;
429	      } catch {
430	        /* ignore */
431	      }
432	
433	      return null;
434	    };
435	
436	    await Promise.all(
437	      imgs.map(async (img) => {
438	        let src = img.getAttribute('src') || '';
439	        // For Google images, request original size (=s0) instead of thumbnail
440	        if (
441	          /^https?:\/\//i.test(src) &&
442	          (src.includes('googleusercontent.com') || src.includes('ggpht.com'))
443	        ) {
444	          const sizePattern = /=[swh]\d+[^?#]*/;
445	          src = sizePattern.test(src) ? src.replace(sizePattern, '=s0') : src + '=s0';
446	        }
447	        const data = await toDataUrl(src);
448	        if (data) {
449	          try {
450	            img.src = data;
451	          } catch {
452	            /* ignore */
453	          }
454	        }
455	      }),
456	    );
457	
458	    await Promise.all(
459	      imgs.map((img) =>
460	        (img as HTMLImageElement & { decode?: () => Promise<void> }).decode?.().catch(() => {
461	          /* ignore */
462	        }),
463	      ),
464	    );
465	  }
