467	  private static async renderWithSafariFallback(container: HTMLElement): Promise<Blob> {
468	    const primaryTarget =
469	      (container.querySelector('.gv-image-export-doc') as HTMLElement | null) || container;
470	    const maxPrimaryAttempts = isSafari() ? 1 : this.PRIMARY_RENDER_MAX_ATTEMPTS;
471	    return await renderElementToImageBlob(primaryTarget, {
472	      maxAttempts: maxPrimaryAttempts,
473	      retryDelayMs: this.PRIMARY_RENDER_RETRY_DELAY_MS,
474	      shouldRetry: (error) => this.shouldRetryPrimaryRender(error),
475	      enableSanitizedFallback: isSafari(),
476	      sanitizeSelector: 'img',
477	      shouldFallback: () => true,
478	    });
479	  }
480	
481	  private static async renderContainerToBlob(container: HTMLElement): Promise<Blob> {
482	    document.body.appendChild(container);
483	
484	    try {
485	      await this.inlineImages(container);
486	      return await this.renderWithSafariFallback(container);
487	    } finally {
488	      try {
489	        container.remove();
490	      } catch {
491	        /* ignore */
492	      }
493	    }
494	  }
495	
496	  private static shouldRetryPrimaryRender(error: unknown): boolean {
497	    if (isEventLikeImageRenderError(error)) return true;
498	
499	    if (error instanceof Error) {
500	      const message = error.message.toLowerCase();
501	      return message.includes('image') || message.includes('decode') || message.includes('network');
502	    }
503	
504	    return false;
505	  }
506	  private static downloadBlob(blob: Blob, filename: string): void {
507	    const url = URL.createObjectURL(blob);
