531	      .replace(/&/g, '&amp;')
532	      .replace(/</g, '&lt;')
533	      .replace(/>/g, '&gt;')
534	      .replace(/"/g, '&quot;')
535	      .replace(/'/g, '&#39;');
536	  }
537	
