539	    const safe = this.escapeHTML(text || '');
540	    if (!safe.trim()) return '<em>No content</em>';
541	    const paras = safe
542	      .split(/\n\n+/)
543	      .map((p) => p.replace(/\n/g, '<br>'))
544	      .map((p) => `<p>${p}</p>`);
545	    return paras.join('');
546	  }
